                    },
                    bases=self.bases,
                    managers=self.managers,
                ),
            ]
        elif (
            isinstance(operation, AlterOrderWithRespectTo)
            and self.name_lower == operation.name_lower
        ):
            return [
                CreateModel(
                    self.name,
                    fields=self.fields,
                    options={
                        **self.options,
                        "order_with_respect_to": operation.order_with_respect_to,
                    },
                    bases=self.bases,
                    managers=self.managers,
                ),
            ]
        elif (
            isinstance(operation, RenameIndex)
            and self.name_lower == operation.model_name_lower
            and operation.old_fields
        ):
            # RenameIndex with old_fields is used to transition from
            # index_together to indexes. Remove the index_together entry
            # and add the index to indexes instead.
            options = self.options.copy()
            index_together = options.get("index_together")
            old_fields_tuple = tuple(operation.old_fields)

            if index_together and old_fields_tuple in index_together:
                # Remove this index from index_together
                new_index_together = {
                    fields for fields in index_together
                    if fields != old_fields_tuple
                }
                if new_index_together:
                    options["index_together"] = new_index_together
                else:
                    options.pop("index_together", None)

                # Add the index to indexes
                indexes = list(options.get("indexes", []))
                indexes.append(
                    models.Index(fields=list(operation.old_fields), name=operation.new_name)
                )
